import{_ as e,o as i,c as l,ak as t}from"./chunks/framework.24mNDJkT.js";const p=JSON.parse('{"title":"集线器学习前置知识：主机直连与交叉线","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/交叉线连接两台主机.md","filePath":"计算机网络/物理层和数据链路层/交叉线连接两台主机.md","lastUpdated":1775135228000}'),r={name:"计算机网络/物理层和数据链路层/交叉线连接两台主机.md"};function s(h,a,n,d,o,c){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="集线器学习前置知识-主机直连与交叉线" tabindex="-1">集线器学习前置知识：主机直连与交叉线 <a class="header-anchor" href="#集线器学习前置知识-主机直连与交叉线" aria-label="Permalink to “集线器学习前置知识：主机直连与交叉线”">​</a></h1><h2 id="一、问题引入-两台主机如何通信" tabindex="-1">一、问题引入：两台主机如何通信？ <a class="header-anchor" href="#一、问题引入-两台主机如何通信" aria-label="Permalink to “一、问题引入：两台主机如何通信？”">​</a></h2><h3 id="场景" tabindex="-1">场景 <a class="header-anchor" href="#场景" aria-label="Permalink to “场景”">​</a></h3><ul><li>两台电脑（主机 A、主机 B）</li><li>想进行： <ul><li>局域网游戏（如红警、魔兽）</li><li>数据通信</li></ul></li></ul><hr><h3 id="初步方案-错误方式" tabindex="-1">初步方案（错误方式） <a class="header-anchor" href="#初步方案-错误方式" aria-label="Permalink to “初步方案（错误方式）”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>主机A —— 普通网线 —— 主机B</span></span></code></pre></div><p>👉 结果：<strong>无法通信</strong></p><hr><h2 id="二、为什么直连不通" tabindex="-1">二、为什么直连不通？ <a class="header-anchor" href="#二、为什么直连不通" aria-label="Permalink to “二、为什么直连不通？”">​</a></h2><h3 id="网卡接口工作原理" tabindex="-1">网卡接口工作原理 <a class="header-anchor" href="#网卡接口工作原理" aria-label="Permalink to “网卡接口工作原理”">​</a></h3><p>网卡接口（RJ45）中：</p><ul><li>不同引脚负责不同功能：</li></ul><table tabindex="0"><thead><tr><th>引脚</th><th>功能</th></tr></thead><tbody><tr><td>1、2</td><td>接收数据</td></tr><tr><td>3、6</td><td>发送数据</td></tr></tbody></table><hr><h3 id="问题本质" tabindex="-1">问题本质 <a class="header-anchor" href="#问题本质" aria-label="Permalink to “问题本质”">​</a></h3><p>普通直连时：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>发送端 → 发送端  </span></span>
<span class="line"><span>接收端 → 接收端</span></span></code></pre></div><p>👉 导致：</p><ul><li>发的数据没人接收 ❌</li><li>收的数据没人发送 ❌</li></ul><hr><h3 id="核心结论" tabindex="-1">核心结论 <a class="header-anchor" href="#核心结论" aria-label="Permalink to “核心结论”">​</a></h3><blockquote><p><strong>同类设备直连，信号方向不匹配 → 无法通信</strong></p></blockquote><hr><h2 id="三、解决方案-交叉线-crossover-cable" tabindex="-1">三、解决方案：交叉线（Crossover Cable） <a class="header-anchor" href="#三、解决方案-交叉线-crossover-cable" aria-label="Permalink to “三、解决方案：交叉线（Crossover Cable）”">​</a></h2><h3 id="原理" tabindex="-1">原理 <a class="header-anchor" href="#原理" aria-label="Permalink to “原理”">​</a></h3><p>👉 将发送与接收线路“交叉”连接：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>A发送 → B接收  </span></span>
<span class="line"><span>B发送 → A接收</span></span></code></pre></div><hr><h3 id="本质" tabindex="-1">本质 <a class="header-anchor" href="#本质" aria-label="Permalink to “本质”">​</a></h3><blockquote><p><strong>交换网线内部引脚顺序</strong></p></blockquote><hr><h3 id="对比" tabindex="-1">对比 <a class="header-anchor" href="#对比" aria-label="Permalink to “对比”">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>连接方式</th><th>是否可通信</th></tr></thead><tbody><tr><td>直通线</td><td>发→发，收→收</td><td>❌</td></tr><tr><td>交叉线</td><td>发→收，收→发</td><td>✅</td></tr></tbody></table><hr><h2 id="四、设备连接规则-重点" tabindex="-1">四、设备连接规则（重点） <a class="header-anchor" href="#四、设备连接规则-重点" aria-label="Permalink to “四、设备连接规则（重点）”">​</a></h2><h3 id="_1️⃣-相同设备" tabindex="-1">1️⃣ 相同设备 <a class="header-anchor" href="#_1️⃣-相同设备" aria-label="Permalink to “1️⃣ 相同设备”">​</a></h3><ul><li>主机 ↔ 主机</li><li>交换机 ↔ 交换机（老设备）</li></ul><p>👉 使用：<strong>交叉线</strong></p><hr><h3 id="_2️⃣-不同设备" tabindex="-1">2️⃣ 不同设备 <a class="header-anchor" href="#_2️⃣-不同设备" aria-label="Permalink to “2️⃣ 不同设备”">​</a></h3><ul><li>主机 ↔ 路由器</li><li>主机 ↔ 交换机</li></ul><p>👉 使用：<strong>直通线</strong></p><hr><h3 id="原因" tabindex="-1">原因 <a class="header-anchor" href="#原因" aria-label="Permalink to “原因”">​</a></h3><blockquote><p>不同设备接口设计已经“内部交叉”</p></blockquote><hr><h2 id="五、仿真验证-packet-tracer" tabindex="-1">五、仿真验证（Packet Tracer） <a class="header-anchor" href="#五、仿真验证-packet-tracer" aria-label="Permalink to “五、仿真验证（Packet Tracer）”">​</a></h2><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to “步骤”">​</a></h3><ol><li>添加两台 PC</li><li>使用交叉线连接</li><li>配置 IP 地址</li></ol><hr><h3 id="示例配置" tabindex="-1">示例配置 <a class="header-anchor" href="#示例配置" aria-label="Permalink to “示例配置”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PC1：192.168.1.10  </span></span>
<span class="line"><span>PC2：192.168.1.11</span></span></code></pre></div><hr><h3 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to “注意”">​</a></h3><ul><li>IP 地址必须： <ul><li><strong>唯一</strong></li><li><strong>同一网段</strong></li></ul></li></ul><hr><h2 id="六、通信验证-ping" tabindex="-1">六、通信验证（Ping） <a class="header-anchor" href="#六、通信验证-ping" aria-label="Permalink to “六、通信验证（Ping）”">​</a></h2><h3 id="命令" tabindex="-1">命令 <a class="header-anchor" href="#命令" aria-label="Permalink to “命令”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.11</span></span></code></pre></div><hr><h3 id="成功标志" tabindex="-1">成功标志 <a class="header-anchor" href="#成功标志" aria-label="Permalink to “成功标志”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>发送 = 4  </span></span>
<span class="line"><span>接收 = 4  </span></span>
<span class="line"><span>丢失 = 0</span></span></code></pre></div><p>👉 说明：</p><ul><li>网络连通 ✅</li></ul><hr><h2 id="七、关键前提-必须有-ip-地址" tabindex="-1">七、关键前提：必须有 IP 地址 <a class="header-anchor" href="#七、关键前提-必须有-ip-地址" aria-label="Permalink to “七、关键前提：必须有 IP 地址”">​</a></h2><h3 id="原因-1" tabindex="-1">原因 <a class="header-anchor" href="#原因-1" aria-label="Permalink to “原因”">​</a></h3><blockquote><p><strong>IP 地址用于标识网络中的主机</strong></p></blockquote><hr><h3 id="如果没有-ip" tabindex="-1">如果没有 IP： <a class="header-anchor" href="#如果没有-ip" aria-label="Permalink to “如果没有 IP：”">​</a></h3><ul><li>无法定位目标主机 ❌</li><li>无法通信 ❌</li></ul><hr><h2 id="八、两种运行模式-仿真工具" tabindex="-1">八、两种运行模式（仿真工具） <a class="header-anchor" href="#八、两种运行模式-仿真工具" aria-label="Permalink to “八、两种运行模式（仿真工具）”">​</a></h2><h3 id="_1️⃣-实时模式-real-time" tabindex="-1">1️⃣ 实时模式（Real-time） <a class="header-anchor" href="#_1️⃣-实时模式-real-time" aria-label="Permalink to “1️⃣ 实时模式（Real-time）”">​</a></h3><ul><li>自动发送数据</li><li>类似真实网络</li></ul><hr><h3 id="_2️⃣-仿真模式-simulation" tabindex="-1">2️⃣ 仿真模式（Simulation） <a class="header-anchor" href="#_2️⃣-仿真模式-simulation" aria-label="Permalink to “2️⃣ 仿真模式（Simulation）”">​</a></h3><ul><li>手动控制数据流</li><li>可观察： <ul><li>数据包传输过程</li><li>各层变化</li></ul></li></ul><hr><h2 id="九、本节核心总结" tabindex="-1">九、本节核心总结 <a class="header-anchor" href="#九、本节核心总结" aria-label="Permalink to “九、本节核心总结”">​</a></h2><h3 id="_1️⃣-主机直连的关键问题" tabindex="-1">1️⃣ 主机直连的关键问题 <a class="header-anchor" href="#_1️⃣-主机直连的关键问题" aria-label="Permalink to “1️⃣ 主机直连的关键问题”">​</a></h3><blockquote><p><strong>发送/接收线路必须匹配</strong></p></blockquote><hr><h3 id="_2️⃣-交叉线的作用" tabindex="-1">2️⃣ 交叉线的作用 <a class="header-anchor" href="#_2️⃣-交叉线的作用" aria-label="Permalink to “2️⃣ 交叉线的作用”">​</a></h3><blockquote><p><strong>实现发送与接收对接</strong></p></blockquote><hr><h3 id="_3️⃣-通信三要素" tabindex="-1">3️⃣ 通信三要素 <a class="header-anchor" href="#_3️⃣-通信三要素" aria-label="Permalink to “3️⃣ 通信三要素”">​</a></h3><ul><li>✔ 正确连接（交叉线）</li><li>✔ 合法 IP 地址</li><li>✔ 同一网段</li></ul><hr><h3 id="_4️⃣-一句话总结" tabindex="-1">4️⃣ 一句话总结 <a class="header-anchor" href="#_4️⃣-一句话总结" aria-label="Permalink to “4️⃣ 一句话总结”">​</a></h3><blockquote><p><strong>两台主机直连必须使用交叉线，并配置正确的 IP 地址，才能实现通信</strong></p></blockquote><hr><h2 id="十、延伸理解-重要" tabindex="-1">十、延伸理解（重要） <a class="header-anchor" href="#十、延伸理解-重要" aria-label="Permalink to “十、延伸理解（重要）”">​</a></h2><p>👉 为什么现实中很少用交叉线？</p><p>因为：</p><ul><li>现代设备支持： <ul><li><strong>Auto MDI/MDIX（自动翻转）</strong></li></ul></li></ul><p>👉 自动识别：</p><ul><li>是否需要交叉</li><li>自动调整发送/接收</li></ul><hr><h2 id="下一步学习重点" tabindex="-1">下一步学习重点 <a class="header-anchor" href="#下一步学习重点" aria-label="Permalink to “下一步学习重点”">​</a></h2><p>👉 <strong>集线器（Hub）</strong></p><p>你会看到：</p><ul><li>为什么交叉线在多设备场景不够用</li><li>集线器是如何“扩展网络”的</li></ul>`,104)])])}const k=e(r,[["render",s]]);export{p as __pageData,k as default};
